INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Newsletter + website publishing$q$, $q$Every issue can be sent as an email and published to a hosted, SEO-friendly website simultaneously from one editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Boosts referral network$q$, $q$A marketplace where publishers pay each other for verified subscriber referrals, giving smaller newsletters a built-in growth channel.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Recommendations network$q$, $q$Cross-promotes a publisher's newsletter to relevant audiences of other beehiiv newsletters to drive organic subscriber growth.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Ad Network$q$, $q$Matches newsletters with sponsors based on audience fit, letting creators monetize through ads without doing their own sponsor outreach.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Paid subscriptions$q$, $q$Supports gated, premium, and tiered newsletter content with no platform cut on subscription revenue beyond payment-processing fees.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Segmentation and automations$q$, $q$Tag- and behavior-based segmentation with automation workflows such as welcome sequences and drip campaigns.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$A/B testing$q$, $q$Built-in split testing for subject lines and content to optimize open and click rates.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Analytics dashboard$q$, $q$Tracks opens, clicks, subscriber growth, and referral sources (Boosts, recommendations, organic) at the post and account level.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Custom domains and website builder$q$, $q$Lets publishers run their newsletter's public site on a custom domain using beehiiv's no-code website builder.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$API and integrations$q$, $q$Offers an API and webhook support for connecting beehiiv data to other tools in a publisher's stack.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Generous free plan (up to 2,500 subscribers) with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$0% platform cut on paid-subscription revenue, beyond standard payment-processing fees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Built-in monetization tools (Ad Network, Boosts) reduce the need for a separate sales effort$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Combines email, website, and analytics in one product, reducing tool sprawl$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Approachable for non-technical writers thanks to a simple block-based editor$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Paid-plan pricing rises quickly as subscriber counts grow$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Marketing automation and segmentation are less sophisticated than dedicated automation platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Design customization can feel template-constrained for teams wanting full custom HTML control$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Ad Network and Boosts eligibility/payouts depend on audience size and niche, so smaller lists see limited benefit early on$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Fewer years of track record than legacy email service providers, which can matter for very high-volume senders$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Is beehiiv free to use?$q$, $q$Yes. Beehiiv's Launch plan is free for up to 2,500 subscribers and includes unlimited email sends plus core newsletter and website tools, with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Does beehiiv take a cut of my subscription revenue?$q$, $q$No. Beehiiv does not take a platform fee on paid-subscription revenue; creators only pay standard third-party payment-processing fees (e.g., Stripe's transaction fees).$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$What is beehiiv mainly used for?$q$, $q$Beehiiv is used to write, send, and grow email newsletters, and to monetize them through paid subscriptions, sponsorships via its Ad Network, and referral-driven growth via Boosts.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Can I migrate my newsletter to beehiiv from another platform?$q$, $q$Yes. Beehiiv supports importing subscriber lists and content from other newsletter platforms such as Substack or Mailchimp, though the specific import process depends on the source platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Does beehiiv support paid newsletters and advertising?$q$, $q$Yes. Beehiiv supports gated paid-subscription tiers directly on the platform and offers an in-house Ad Network that connects newsletters with sponsors based on audience fit.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Launching an independent newsletter from scratch$q$, $q$Solo writers use beehiiv's free plan to start publishing, build a website presence, and grow an audience before investing in paid tools.$q$, $q$Independent writers and solo creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Running multiple newsletter brands under one account$q$, $q$Media teams manage several distinct newsletters, each with its own site and list, from a single beehiiv account instead of juggling separate ESP subscriptions.$q$, $q$Digital media publishers and small editorial teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Monetizing an audience through subscriptions and sponsorships$q$, $q$Established creators turn a free newsletter into a revenue stream using paid subscription tiers and beehiiv's Ad Network for sponsorships.$q$, $q$Full-time newsletter creators and influencers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Using a newsletter as a content-marketing channel$q$, $q$Businesses publish a branded newsletter to nurture leads and build a first-party audience, relying on beehiiv's website and analytics tools for distribution and tracking.$q$, $q$B2B and B2C marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Launch$q$, $q$Free$q$, NULL, $q$["Up to 2,500 subscribers","Unlimited email sends","Hosted website builder","Core newsletter and website tools","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Scale$q$, $q$From $43/month$q$, $q$annual$q$, $q$["Paid subscriptions with no platform revenue cut","Access to the Ad Network","Boosts referral growth network","Automations and advanced segmentation","Custom domain and advanced analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Max$q$, $q$From $96/month$q$, $q$annual$q$, $q$["Everything in Scale","Remove beehiiv branding","Dynamic/personalized content","Priority support","Up to 10 publications"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["For 100,000+ subscribers","Custom contract terms","Dedicated support","Advanced onboarding and migration assistance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Beehiiv is a newsletter and content-publishing platform launched in 2021 by Tyler Denk along with fellow alumni of Morning Brew, the business newsletter that scaled to millions of subscribers before its acquisition. Denk led engineering and growth at Morning Brew, and he built beehiiv to package the growth and monetization tactics that worked there into a self-serve product for independent writers and media companies.$q$, $q$The platform combines an email-sending engine, a hosted website builder, and audience-growth tools — a referral system called Boosts, a cross-newsletter Recommendations network, and an in-house Ad Network — inside a single dashboard, positioning itself less as a traditional email service provider and more as an end-to-end publishing business in a box.$q$, $q$Beehiiv has become one of the more visible names in the modern newsletter economy, used by solo writers, niche B2B publications, and larger digital media operations that run several newsletter brands from one account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$who-its-for$q$, $q$Who Beehiiv Is For$q$, 2, ARRAY[$q$Beehiiv is aimed squarely at people who treat their newsletter as a media property or standalone business rather than a marketing channel bolted onto an existing website. Independent writers looking to turn a hobby newsletter into a paid-subscription or ad-supported publication are the platform's core audience.$q$, $q$It also suits small media teams and multi-brand publishers who need to run several distinct newsletters, each with its own website and subscriber list, without paying for multiple separate email-service accounts. The built-in Ad Network and Boosts referral marketplace are especially valuable to creators who lack a sales team or growth budget but still want passive discovery and monetization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Beehiiv is a weaker fit for teams whose primary need is deep marketing automation, multi-channel customer journeys, or CRM-grade lead scoring — the kind of workflows tools like ActiveCampaign or HubSpot are built around. Its automation and segmentation features are solid for a newsletter business but shallower than those in dedicated marketing-automation suites.$q$, $q$Companies that already run established transactional or marketing-email infrastructure and just need a bare-bones sender, or that require pixel-perfect custom HTML design beyond what its block editor and templates offer, may find beehiiv more restrictive than expected as their needs grow.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Beehiiv's editor covers both the newsletter and a hosted website, so writers can publish an issue, have it land in inboxes, and simultaneously post it to a public, SEO-indexable web page without extra tools. Segmentation, A/B subject-line testing, and automation workflows such as welcome series or tag-based triggers sit alongside standard list-management features.$q$, $q$Its real differentiators are the growth and monetization layer: Boosts lets publishers pay each other for verified subscriber referrals; the Recommendations network cross-promotes newsletters to each other's audiences; and the Ad Network matches sponsors with newsletters that fit their target audience, without publishers needing to find sponsors themselves. Paid subscriptions — gated content, tiers, and premium newsletters — run through beehiiv with no platform cut on subscription revenue, only standard payment-processing fees.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', $q$the-beehiiv-experience$q$, $q$The Beehiiv Publishing Experience$q$, 2, ARRAY[$q$Day to day, beehiiv feels closer to a lightweight CMS with an email button than a classic email service provider: writers draft in a block-based editor, preview both the email and web versions, and publish once. Analytics surface open, click, and growth data per post, with subscriber-source breakdowns showing how much of an audience came from Boosts, recommendations, or organic sign-up.$q$, $q$The free Launch plan is generous enough for most people to test the product for months before paying, and upgrading to a paid tier unlocks monetization features rather than gating core publishing tools — a structure that tends to appeal to writers who want to prove an audience exists before spending money on growing it.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
