INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff227d86-ddbd-4dae-a781-076d3958c64f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Proposal templates & content library$q$, $q$A library of industry-specific templates and reusable content blocks (case studies, bios, terms) speeds up building consistent, on-brand proposals.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Interactive pricing tables$q$, $q$Clients can select packages, quantities, or add-ons directly inside the proposal, updating the total price in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Legally binding e-signatures$q$, $q$Clients sign proposals and contracts electronically inside the same document, with no separate e-signature tool needed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Built-in payment collection$q$, $q$Payment integrations let a signed proposal trigger an immediate deposit or invoice payment, tying the win to cash collection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Document tracking & notifications$q$, $q$Senders are alerted when a proposal is opened and can see time spent on each section, helping gauge client interest before following up.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$CRM integrations$q$, $q$Native connections to CRMs such as HubSpot, Salesforce, and Pipedrive (Premium and above) keep proposal status in sync with the sales pipeline.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$API & Zapier$q$, $q$An API and Zapier connection let proposals be triggered from, or reported back to, other sales and project-management tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Automated follow-up (Nudge)$q$, $q$An add-on automation feature that re-engages clients who haven't opened or signed a sent proposal, without manual chasing.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Custom domains & brand customization$q$, $q$Proposals can be sent from a custom domain with full brand styling, so the document looks like a native part of the sender's website.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Content locking & team permissions$q$, $q$Enterprise-tier controls restrict which content a recipient sees and add manager-approval steps and granular user permissions for larger teams.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Fast to get a polished, on-brand proposal out using pre-built templates and content blocks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$E-signature and payment collection are built into the same document, reducing tool-switching$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Real-time open/view tracking gives useful signal on how engaged a prospect is$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Interactive, web-based proposals feel more modern than a static PDF and work well on mobile$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Straightforward, transparent per-seat pricing with a 14-day free trial and no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Starter plan is capped at a single user and a limited number of monthly documents$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$CRM integrations, API/Zapier access, and custom domains are locked behind the Premium tier or higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$No permanent free plan, only a time-limited trial$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Advanced collaboration features (simultaneous editing, content locking, approvals) require the top Enterprise tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Not built for complex CPQ or contract-lifecycle-management needs beyond proposal sending$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$What is Better Proposals used for?$q$, $q$Better Proposals is used to create, send, track, and get e-signatures and payments on sales proposals, quotes, and contracts, replacing static Word or PDF documents with an interactive web-based proposal.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Does Better Proposals have a free plan?$q$, $q$There is no permanent free plan. Better Proposals offers a 14-day free trial that doesn't require a credit card, after which users choose a paid Starter, Premium, or Enterprise plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Can clients pay directly through a Better Proposals document?$q$, $q$Yes. Better Proposals supports built-in payment collection, so once a client signs a proposal they can be prompted to pay a deposit or invoice within the same document.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Does Better Proposals integrate with CRMs like HubSpot or Salesforce?$q$, $q$Yes, CRM integrations are available starting on the Premium plan, along with an API and Zapier connection for linking proposals to other sales tools.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Is Better Proposals suitable for large enterprise sales teams?$q$, $q$It can work for larger teams via the Enterprise plan, which adds approval workflows, content locking, and advanced permissions, but it is primarily built for freelancers, agencies, and small-to-mid-size teams rather than complex enterprise CPQ needs.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Freelance proposal & deposit collection$q$, $q$A freelancer builds a proposal from a template, sends it as a trackable link, and collects a signature and upfront deposit payment in one step.$q$, $q$Freelancers and solo consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Agency new-business pitching$q$, $q$A marketing or design agency reuses branded content blocks and case studies to quickly assemble consistent, professional pitches for prospective clients.$q$, $q$Marketing and creative agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Sales team pipeline integration$q$, $q$A small sales team sends proposals that sync status back to their CRM, and uses automated follow-up nudges to re-engage prospects who haven't responded.$q$, $q$Small B2B sales teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Multi-brand, multi-language proposal sending$q$, $q$A business serving clients in different countries sets up separate brands, each configured in a different language and currency, to send localized proposals.$q$, $q$Businesses selling to international clients$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Starter$q$, $q$$13/user/month (billed annually) or $19/user/month (billed monthly)$q$, $q$monthly or annual$q$, $q$["1 user seat","Up to 10 documents per month","Digital signatures","Interactive pricing tables","Payment integrations","Content library","Tracking & notifications"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Premium$q$, $q$$21/user/month (billed annually) or $29/user/month (billed monthly)$q$, $q$monthly or annual$q$, $q$["Unlimited user seats","Up to 50 documents per month","Everything in Starter","Custom domain","CRM integrations","Automatic expiry dates","API & Zapier access","Custom onboarding flows"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$Enterprise$q$, $q$$42/user/month (billed annually) or $49/user/month (billed monthly)$q$, $q$monthly or annual$q$, $q$["Unlimited user seats","Unlimited documents","Everything in Premium","Content locking","Simultaneous editing","Inline commenting","Manager approvals","Advanced permissions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Better Proposals is a web-based proposal and e-signature platform built to help freelancers, agencies, and small businesses replace Word documents, PDFs, and PowerPoint decks with interactive, trackable sales proposals. The company was founded in Brighton, England, in 2015 by Adam Hempenstall, who built the first version after growing frustrated with how long it took his own design agency to put together polished, professional-looking proposals. It has since grown into a bootstrapped, fully remote software company with thousands of paying customers across freelance, agency, and small-business segments.$q$, $q$At its core, Better Proposals lets users start from a library of industry-specific templates, customize the content and branding, and send a proposal as a hosted web page rather than a static file. Clients can view the proposal on any device, sign it electronically, and in many cases pay a deposit or invoice on the spot, since payment collection is built directly into the document rather than handled as a separate step. Senders get real-time tracking on whether a proposal has been opened, how long the recipient spent on each section, and when it was signed.$q$, $q$The product is positioned as a simpler, more focused alternative to broader CPQ (configure-price-quote) suites: it does not try to be a full sales or contract-lifecycle platform, and instead concentrates on making the proposal-to-signature-to-payment sequence fast and professional-looking with minimal setup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$who-its-for$q$, $q$Who Better Proposals Is For$q$, 2, ARRAY[$q$Better Proposals is aimed squarely at people who send sales proposals, quotes, or contracts on a recurring basis and want to look professional without hiring a designer or writer for every document. Freelancers and solo consultants are a core audience, since the Starter plan is priced and capped for a single user sending a modest volume of documents per month. Marketing agencies, web design and development shops, and other creative or professional-services firms are a natural fit too, given the template library is heavily weighted toward those industries and the tool is built to make proposals look polished with minimal formatting effort.$q$, $q$It also suits small sales teams that want built-in CRM integrations (HubSpot, Salesforce, Pipedrive, and others), automated follow-up nudges, and e-signature plus payment collection in one workflow, without adopting a heavier enterprise sales platform. Because pricing and document/user limits scale up through Premium and Enterprise tiers, growing teams that need more seats, custom domains, or approval workflows can upgrade rather than switching tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Better Proposals is less suitable for large enterprises with complex, multi-department approval chains, deep CPQ or contract-lifecycle-management needs, or requirements for extensive custom integrations beyond what Zapier and the native CRM connectors cover; those buyers are typically better served by dedicated CPQ or CLM platforms with more configurable workflow engines. Very high-volume senders on a tight budget should also check the document caps carefully, since the entry-level Starter plan is limited to a single user and a capped number of documents per month, and features like CRM integrations only unlock on the Premium tier and above.$q$, $q$Teams that specifically need native iOS or Android apps, rather than a responsive web experience, may also find the product's mobile-web-only approach limiting. Finally, buyers hoping for a permanently free plan should look elsewhere, since Better Proposals offers only a time-limited free trial rather than an ongoing free tier.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Better Proposals' feature set centers on six connected stages: creating a document from a template, sending it as an interactive web page, following up automatically, capturing a legally binding e-signature, onboarding the client with forms and payment collection, and managing the proposal process across a team. The template and content-block library covers dozens of industries, and a shared content library lets teams reuse approved copy, case studies, and pricing tables across documents so proposals stay consistent and fast to assemble.$q$, $q$On the sales-operations side, the platform includes interactive pricing tables that let clients choose options or add-ons directly inside the proposal, built-in payment collection (so a signed proposal can trigger an invoice or deposit charge immediately), and tracking/notifications that tell the sender when a document is opened, viewed, or signed. Premium and Enterprise plans add CRM integrations, an API and Zapier connection for wiring proposals into other sales tools, custom domains for white-labeled sending, and an automated follow-up feature (branded 'Nudge') that re-engages clients who haven't opened or signed.$q$, $q$Higher tiers also add team- and security-oriented controls: content locking to restrict which sections a given recipient can see, simultaneous multi-user editing and inline commenting for internal collaboration, manager approval steps before a document goes out, and more granular user permissions — features aimed at agencies and larger teams that need oversight without slowing down the sending process.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', $q$the-proposal-to-close-experience$q$, $q$The Proposal-to-Close Experience$q$, 2, ARRAY[$q$In practice, using Better Proposals starts with picking a template or content block that matches the type of deal being proposed, then customizing the copy, pricing tables, and branding inside a browser-based editor rather than a desktop word processor. Because the finished document is a responsive web page rather than a downloadable file, the sender can drop in embedded video, testimonials, or interactive pricing options that a PDF cannot easily support, and the same document looks correct whether the client opens it on a laptop or a phone.$q$, $q$Once sent, the workflow shifts to tracking: the sender gets notified as soon as the proposal is opened and can see engagement at a section level, which is useful for judging how warm a lead is before following up. When the client is ready, they sign electronically inside the same page, and if payment is part of the deal, they can pay a deposit or the full invoice immediately afterward, collapsing what is normally a multi-step, multi-tool process (send a PDF, chase a signature, then send a separate invoice) into a single continuous flow.$q$, $q$For teams on Premium or Enterprise, that same document can also be wired into a CRM so proposal status updates automatically, or set up with an approval step so a manager signs off before it reaches the client — letting solo freelancers and larger agency teams use broadly the same core tool at different levels of process rigor.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
