INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c9d0a5-64da-46ca-b8b7-a7245a366020', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Open APIs & headless commerce$q$, $q$GraphQL Storefront API and the Catalyst (Next.js) framework let developers decouple the front end from the BigCommerce backend for fully custom or composable storefronts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Built-in multichannel selling$q$, $q$Native integrations connect the catalog and orders to marketplaces and social channels including Amazon, eBay, Walmart, Facebook, and Instagram.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$B2B Edition$q$, $q$Purpose-built wholesale tools covering customer-specific catalogs and pricing, quoting, purchase orders, and account hierarchies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Multi-storefront$q$, $q$Run multiple branded storefronts from a single BigCommerce backend and shared product catalog.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Customizable SEO controls$q$, $q$Editable URLs, canonical tags, meta fields, and sitemap generation give merchants direct control over on-page SEO.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Stencil theme framework$q$, $q$A templating system for building or customizing storefront themes, supplemented by the Makeswift visual/headless page builder.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Multi-currency support$q$, $q$Native support for displaying and transacting in multiple currencies for international selling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Abandoned cart recovery$q$, $q$Built-in automated emails to recover abandoned checkouts without requiring a separate app.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Open payment gateway choice$q$, $q$Merchants can choose from a range of supported payment providers rather than being locked into a single proprietary processor.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Deep native/built-in functionality (multi-currency, B2B, faceted search) reduces reliance on third-party apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Strong headless and API-first architecture (GraphQL Storefront API, Catalyst) appeals to developers and enterprise teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Robust built-in B2B tools (quoting, customer groups, purchase orders) without a separate platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Flexible, developer-friendly SEO controls over URLs, canonicals, and sitemaps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Choice of payment gateway rather than a single mandated processor$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Sales-based plan thresholds automatically push growing stores into higher-priced tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Smaller third-party app and theme marketplace compared to Shopify$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Steeper learning curve and heavier reliance on developers/agencies for deep customization$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Less mature integrated POS/omnichannel retail hardware ecosystem for physical stores$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$New Open Payment Provider Fee (added June 2026) charges up to ~2% of GMV — including offline and B2B purchase-order transactions — on orders not processed through an approved embedded payment provider$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Is BigCommerce free to use?$q$, $q$No, BigCommerce does not have a permanent free plan, but it offers a free trial so merchants can test the platform before committing to a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Does BigCommerce still charge no transaction fees?$q$, $q$Historically BigCommerce marketed itself as charging no transaction fees regardless of payment gateway. As of June 2026, it introduced an Open Payment Provider Fee (roughly 2% on the entry-level Core plan, lower on higher tiers) that applies to orders processed through a gateway outside its approved embedded-payments list, including offline and purchase-order transactions.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$What happens if my store exceeds its plan's annual sales threshold?$q$, $q$BigCommerce plans are tied to annual online sales volume; stores that exceed their current plan's threshold are automatically moved to the next pricing tier.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Can BigCommerce be used as a headless commerce backend?$q$, $q$Yes. BigCommerce offers a GraphQL Storefront API and the Catalyst framework (built on Next.js) so developers can build a fully custom front end while using BigCommerce for catalog, checkout, and order management.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Is BigCommerce good for B2B and wholesale selling?$q$, $q$Yes. BigCommerce's B2B Edition includes quoting, customer-specific catalogs and pricing, purchase orders, and account hierarchies built directly into the platform.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Scaling past an entry-level platform$q$, $q$Mid-market retailers that have outgrown basic cart software use BigCommerce's native features (multi-currency, faceted search, advanced promotions) to avoid stacking on many paid apps.$q$, $q$Growing DTC and mid-market retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$B2B and wholesale storefronts$q$, $q$Wholesalers and manufacturers use the B2B Edition to manage customer-specific pricing, quoting, and purchase orders alongside a standard retail storefront.$q$, $q$B2B distributors and wholesalers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Multichannel retail$q$, $q$Sellers list and fulfill across Amazon, eBay, Walmart, and social channels from one BigCommerce back office instead of managing each channel separately.$q$, $q$Multichannel and marketplace sellers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Headless/composable commerce builds$q$, $q$Agencies and in-house dev teams build custom React/Next.js front ends on top of BigCommerce's GraphQL Storefront API using the Catalyst framework.$q$, $q$Developers and digital agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Core (formerly Standard)$q$, $q$$39/month billed monthly, or $29/month billed annually$q$, $q$monthly or annual$q$, $q$["Unlimited products and staff accounts","Faceted search","Multi-currency selling","Abandoned cart recovery","Standard support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Growth (formerly Plus)$q$, $q$$105/month billed monthly, or $79/month billed annually$q$, $q$monthly or annual$q$, $q$["Customer groups & segmentation","Stored credit card details for faster checkout","Product filtering","Everything in Core"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Scale (formerly Pro)$q$, $q$$399/month billed monthly, or $299/month billed annually$q$, $q$monthly or annual$q$, $q$["Google Customer Reviews integration","Custom SSL support","Higher API rate limits","Everything in Growth"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$Performance (formerly Enterprise)$q$, $q$Custom pricing$q$, NULL, $q$["Multi-storefront","Dedicated account support","B2B Edition access","Custom SLAs and highest API limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BigCommerce is a publicly traded (Nasdaq: BIGC) software-as-a-service ecommerce platform founded in 2009 in Sydney, Australia, and now headquartered in Austin, Texas. It lets merchants build, host, and manage an online store without maintaining their own servers or codebase, positioning itself as an 'open SaaS' alternative that pairs the convenience of a hosted platform with deep API access and fewer artificial feature restrictions than some rivals.$q$, $q$The platform competes directly with Shopify, Adobe Commerce (Magento), and Salesforce Commerce Cloud, and is often chosen by merchants that have outgrown entry-level cart software but don't want the overhead of a fully self-managed open-source stack. Its plans are structured around annual online sales thresholds rather than flat feature gates alone, so stores are nudged into higher tiers as revenue grows.$q$, $q$BigCommerce operates as part of a broader company that also owns Feedonomics (multichannel catalog syndication) and Makeswift (a headless page-building tool), reflecting a strategy of bundling commerce, feed management, and composable front-end tooling around the core BigCommerce SaaS product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$who-bigcommerce-is-for$q$, $q$Who BigCommerce Is For$q$, 2, ARRAY[$q$BigCommerce suits growing mid-market and enterprise retailers that need more native functionality — multi-currency, faceted search, customer groups, advanced discounting — built into the core platform instead of stitched together from third-party apps. This reduces long-term app subscription costs and app-conflict risk as a catalog and traffic scale.$q$, $q$It's also a strong fit for B2B and wholesale sellers, since BigCommerce's B2B Edition provides quoting, customer-specific catalogs and pricing, purchase orders, and account hierarchies without requiring a separate B2B platform bolted onto the storefront.$q$, $q$Developers and agencies building composable or headless storefronts are another natural audience: BigCommerce's GraphQL Storefront API and its Catalyst framework (a Next.js-based starter kit) let technical teams decouple the front end from the commerce backend while still using BigCommerce for catalog, checkout, and order management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small merchants or first-time store owners who just need to get a simple store live quickly may find Shopify's larger app and theme marketplace, simpler onboarding, and more abundant tutorials and agency support a gentler starting point than BigCommerce.$q$, $q$Retailers who rely heavily on integrated point-of-sale hardware for physical, in-person retail should weigh alternatives too — BigCommerce's omnichannel POS ecosystem is less mature than Shopify's, which was built POS-first for brick-and-mortar sellers.$q$, $q$Merchants who want one flat, predictable cost structure regardless of payment processor should also read the fine print carefully: as of June 2026, BigCommerce introduced an Open Payment Provider Fee (roughly 2% on its entry plan, scaling down on higher tiers) that applies to orders — including offline and purchase-order transactions — processed through a gateway outside its approved embedded-payments list. Businesses locked into a non-approved processor may find the economics less attractive than before.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, BigCommerce provides hosted storefront themes (Stencil framework), a visual and headless page-building option via Makeswift, cart and checkout management, and built-in SEO controls such as customizable URLs, canonical tags, and sitemap generation — giving merchants more direct control over on-page SEO than some closed platforms allow.$q$, $q$Multichannel selling is a strong point: native or first-party-supported integrations connect stores to Amazon, eBay, Walmart, Facebook, Instagram, and Google, letting merchants manage inventory and orders from multiple sales channels in one back office. Multi-storefront capability lets larger merchants run several branded storefronts from a single backend and catalog.$q$, $q$For technical and B2B use cases, the GraphQL Storefront API, webhooks, and the B2B Edition (quoting, customer groups, negotiated pricing, purchase orders) round out a feature set aimed at merchants who need more than a basic cart-and-checkout tool.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', $q$the-bigcommerce-experience$q$, $q$The BigCommerce Experience$q$, 2, ARRAY[$q$Day-to-day, BigCommerce's admin dashboard covers catalog, orders, customers, and marketing in a fairly conventional ecommerce back-office layout. Merchants who want a fully custom look typically work with a developer or agency to build or heavily modify a Stencil theme, or adopt a headless approach through Makeswift or Catalyst rather than relying purely on off-the-shelf templates.$q$, $q$Support is tiered by plan, with higher-tier and Enterprise-level (Performance-tier) customers getting more dedicated account support, while BigCommerce also maintains a partner network of agencies and a smaller third-party app marketplace than Shopify's, meaning some customizations lean more on custom development than on install-and-go apps.$q$, $q$Overall, BigCommerce rewards merchants willing to invest a bit more up front — technically or through an agency — with a platform that scales cleanly into B2B, multichannel, and headless use cases; store owners wanting the fastest, most turnkey setup with the largest app ecosystem may still prefer a more consumer-oriented platform.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3103af2-b89a-4cb2-ac57-83030df19efa', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
