INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Real-time malware protection$q$, $q$Multi-layered scanning engine combining signatures, heuristics, and cloud-based machine learning to detect viruses, spyware, and zero-day threats.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Multi-layer ransomware protection$q$, $q$Monitors documents and photos for unauthorized encryption and can back up and restore files affected by a ransomware attack.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Safepay secure browser$q$, $q$An isolated browser environment for online banking and shopping that shields sessions from screen capture, keyloggers, and other browsers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Firewall and network threat prevention$q$, $q$An adaptive firewall plus network-level filtering that blocks intrusion attempts, port scans, and brute-force attacks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$VPN$q$, $q$Built-in VPN for encrypting internet traffic; capped at 200MB/day on entry-level plans, unlimited on Premium Security.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Password manager$q$, $q$Stores and autofills logins and payment details, with a browser extension across supported platforms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Parental controls$q$, $q$Content filtering, screen-time limits, and location tracking to help manage children's device use, included from Internet Security up.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Anti-phishing and anti-fraud$q$, $q$Blocks known fraudulent and phishing websites in the browser before users can enter credentials or payment data.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Webcam and microphone protection$q$, $q$Alerts and blocks unauthorized applications from accessing the device's camera or microphone.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$GravityZone (business)$q$, $q$Cloud-managed endpoint protection platform for organizations, with optional EDR, XDR, and managed detection and response (MDR) services.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Consistently top-rated malware detection rates in independent AV-Test and AV-Comparatives lab tests$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Low system performance impact thanks to Autopilot/Photon adaptive scanning$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Broad cross-platform support (Windows, macOS, Android, iOS) under one subscription on higher tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Comprehensive feature set — firewall, VPN, password manager, parental controls, and anti-theft tools bundled together$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Scales from a free consumer scanner up to enterprise-grade GravityZone EDR/XDR for businesses$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Renewal pricing is significantly higher than first-year introductory pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$VPN is capped at 200MB/day unless upgrading to Premium Security or buying it separately$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Free edition is Windows-only and stripped down compared to paid suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Interface can push upsells and add-on offers fairly often$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Limited native Linux support on the consumer product line$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Is Bitdefender free to use?$q$, $q$Bitdefender offers a free antivirus scanner for Windows (Bitdefender Antivirus Free Edition) with core real-time protection, but advanced features like firewall, VPN, parental controls, and password manager require a paid Internet Security, Total Security, or Premium Security subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$What platforms does Bitdefender support?$q$, $q$Bitdefender supports Windows and, depending on the plan, macOS, Android, and iOS. Total Security and Premium Security are the cross-platform tiers, while Antivirus Plus and Internet Security are Windows-only.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Does Bitdefender slow down my computer?$q$, $q$Bitdefender is generally regarded as lightweight due to its Photon technology and Autopilot mode, which adapt scanning behavior to the device's hardware and usage patterns, and it typically performs well in independent performance benchmarks.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$What is the difference between Bitdefender's consumer products and GravityZone?$q$, $q$The consumer suites (Antivirus Plus, Internet Security, Total Security, Premium Security) are aimed at individuals and families, while GravityZone is Bitdefender's business platform, offering centrally managed endpoint protection with optional EDR, XDR, and MDR services for organizations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Does Bitdefender include a VPN?$q$, $q$Yes, a VPN is bundled into paid consumer plans, though it's limited to 200MB of traffic per day on lower tiers; unlimited VPN usage is included only with Premium Security or as a separate add-on purchase.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Everyday home antivirus protection$q$, $q$A household wants reliable, low-maintenance malware and ransomware protection for a Windows PC without needing to configure or manage security settings manually.$q$, $q$Individual home users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Family device and content management$q$, $q$Parents use Internet Security or Total Security to filter web content, set screen-time limits, and monitor children's devices alongside standard antivirus protection.$q$, $q$Families with children$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Cross-platform household security$q$, $q$A user with a Windows laptop, a Mac, an Android phone, and an iPad consolidates protection for all devices under a single Total Security or Premium Security subscription.$q$, $q$Multi-device consumers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Centrally managed business endpoint security$q$, $q$A small or mid-sized company deploys GravityZone to protect employee laptops and servers from a single cloud console, with optional managed detection and response support.$q$, $q$Small and mid-sized business IT teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Antivirus Free Edition$q$, $q$Free$q$, NULL, $q$["Real-time antivirus protection","Windows only","Minimal interface with autopilot scanning","No firewall, VPN, or parental controls"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Antivirus Plus$q$, $q$From ~$29.99/year (introductory pricing, Windows, 3 devices)$q$, $q$annual$q$, $q$["Multi-layer ransomware protection","Safepay secure browser","Password manager","VPN (200MB/day)","Vulnerability assessment"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Total Security$q$, $q$From ~$49.99/year (introductory pricing, up to 5 devices)$q$, $q$annual$q$, $q$["Cross-platform: Windows, macOS, Android, iOS","Everything in Internet Security","Parental controls","System optimizer and file shredder","Anti-theft tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$Premium Security$q$, $q$From ~$89.99/year (introductory pricing, up to 10 devices)$q$, $q$annual$q$, $q$["Everything in Total Security","Unlimited VPN traffic","Premium password manager","Priority customer support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bitdefender is a cybersecurity company founded in 2001 and headquartered in Bucharest, Romania, where it grew out of the antivirus division of Romanian software firm Softwin before becoming an independent company. Over more than two decades it has built one of the most recognized security engines in the industry, licensing its detection technology to other vendors while also selling its own branded consumer and business products worldwide.$q$, $q$On the consumer side, Bitdefender sells a tiered lineup of Windows, Mac, Android, and iOS security suites — Antivirus Plus, Internet Security, Total Security, and Premium Security — plus a free, ad-supported antivirus scanner for Windows. For organizations, its GravityZone platform provides endpoint detection and response (EDR), extended detection and response (XDR), and managed detection and response (MDR) services for businesses of varying sizes. Bitdefender's malware-detection engine consistently ranks near the top in independent testing labs such as AV-Test and AV-Comparatives, which is a major part of its reputation and marketing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$who-its-for$q$, $q$Who Bitdefender Is For$q$, 2, ARRAY[$q$Bitdefender is a strong fit for everyday home users who want a 'set it and forget it' antivirus that runs quietly in the background without requiring constant manual scans or configuration — its Autopilot mode is built around this idea, making silent security decisions on the user's behalf. Families are also a core audience: Internet Security and Total Security add parental controls, webcam/microphone protection, and anti-phishing tools that help protect children and less tech-savvy household members.$q$, $q$It also suits people who own a mix of devices, since Total Security and Premium Security extend a single subscription across Windows, macOS, Android, and iOS, bundling a password manager, file shredder, and limited VPN in one dashboard (Bitdefender Central). On the business side, small and mid-sized companies that need centrally managed endpoint protection — without building an in-house security operations team — are well served by GravityZone's cloud-managed console and optional MDR add-on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who want a single free product with full-featured protection long-term may be frustrated: the free Antivirus Free Edition is Windows-only, deliberately stripped down, and Bitdefender pushes upsells toward the paid suites through in-app notifications. Linux desktop users and anyone needing broad native Linux endpoint support outside of GravityZone will find consumer-side coverage limited.$q$, $q$Price-sensitive shoppers who dislike steep subscription renewal increases should also be cautious — like most consumer antivirus vendors, Bitdefender's first-year promotional pricing is typically far lower than the renewal rate, so it's worth checking the renewal price before committing. Similarly, technically confident users who prefer a lightweight, single-purpose antivirus with no bundled VPN, password manager, or optimizer may find the higher suites feature-heavy relative to what they actually need.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Bitdefender relies on a multi-layered detection engine combining signature-based scanning, heuristics, behavioral analysis, and cloud-based machine learning to catch malware, ransomware, and zero-day threats in real time. Multi-layer ransomware protection monitors documents and photos for unauthorized encryption attempts and can automatically back up and restore affected files, while a dedicated Safepay browser isolates online banking and shopping sessions from the rest of the system.$q$, $q$Network-facing protections include an adaptive firewall, anti-phishing and anti-fraud filtering, a network threat prevention layer, and (in paid tiers) a VPN — capped at 200MB/day on lower tiers and unlimited on Premium Security. Privacy and household tools round out the suite: a password manager, webcam/microphone blocking, anti-tracker browser extension, parental controls, and a file shredder for permanently deleting sensitive files.$q$, $q$Performance and manageability are also emphasized. 'Autopilot' and Bitdefender's Photon technology adapt scanning behavior to the device's hardware and usage patterns to minimize slowdowns, and the Bitdefender Central web/mobile app lets users manage protection, subscriptions, and devices from one place. Businesses get an analogous central console through GravityZone, with endpoint hardening, risk analytics, and optional EDR/XDR/MDR modules.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', $q$experience$q$, $q$The Bitdefender Experience$q$, 2, ARRAY[$q$Installation is straightforward: Bitdefender typically runs a quick system scan on setup, then settles into Autopilot mode, making most security decisions silently and only surfacing notifications for things that need user input, such as a blocked website or a detected threat. Day-to-day, most users interact with the product mainly through occasional pop-up alerts and the Bitdefender Central dashboard, where devices, subscriptions, and add-ons (like the VPN or identity protection) are managed.$q$, $q$Some reviewers and long-time users note that Bitdefender can be more assertive than competitors about promoting upgrades to higher tiers or add-on services within the app. Customer support is available via live chat, phone, and a knowledge base, and enterprise customers using GravityZone get a more hands-on onboarding and account-management experience than consumer users typically receive.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('71dcd814-d7ea-4382-b7e3-3238f93f3360', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
